import heapq


class FoodRatings:
    def __init__(self, foods, cuisines, ratings):
        self.rating = {}
        self.cuisine = {}
        self.heaps = {}
        for f, c, r in zip(foods, cuisines, ratings):
            self.rating[f] = r
            self.cuisine[f] = c
            self.heaps.setdefault(c, []).append((-r, f))
        for c in self.heaps:
            heapq.heapify(self.heaps[c])
    def changeRating(self, food, newRating):
        self.rating[food] = newRating
        heapq.heappush(self.heaps[self.cuisine[food]], (-newRating, food))
        return None
    def highestRated(self, cuisine):
        h = self.heaps[cuisine]
        while h:
            negr, f = h[0]
            if -negr == self.rating[f]:
                return f
            heapq.heappop(h)
        return None

