class FoodRatings {
    constructor(foods, cuisines, ratings) {
        this.rating = new Map();
        this.cuisine = new Map();
        this.groups = new Map();
        for (let i = 0; i < foods.length; i++) {
            this.rating.set(foods[i], ratings[i]);
            this.cuisine.set(foods[i], cuisines[i]);
            if (!this.groups.has(cuisines[i])) this.groups.set(cuisines[i], []);
            this.groups.get(cuisines[i]).push(foods[i]);
        }
    }
    changeRating(food, newRating) {
        this.rating.set(food, newRating);
        return null;
    }
    highestRated(cuisine) {
        let best = null;
        for (const f of this.groups.get(cuisine)) {
            const r = this.rating.get(f);
            if (best === null || r > best[0] || (r === best[0] && f < best[1])) {
                best = [r, f];
            }
        }
        return best[1];
    }
}
